import{_ as t,o as e,c as i,a4 as s}from"./chunks/framework.DyvFOq6U.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Typst 練習場","text":"Learn Typst by Doing","tagline":"一個中英雙語的互動式 Typst 排版練習網站 / A bilingual interactive Typst practice site","image":{"src":"/logo.svg","alt":"Typst Practice"},"actions":[{"theme":"brand","text":"開始學習 / Start Learning","link":"/guide/quick-start"},{"theme":"alt","text":"互動沙盒 / Sandbox","link":"/sandbox/"}]},"features":[{"icon":"📖","title":"雙語教學 / Bilingual Tutorial","details":"所有教學內容皆提供繁體中文與英文對照，適合不同語言背景的學習者。All tutorials available in Traditional Chinese and English.","link":"/guide/quick-start"},{"icon":"🛠️","title":"互動沙盒 / Interactive Sandbox","details":"瀏覽器內即時編譯 Typst 程式碼，所見即所得，不需安裝任何軟體。Real-time Typst compilation in browser — no installation needed.","link":"/sandbox/"},{"icon":"📐","title":"涵蓋基礎 / Covering the Basics","details":"頁面設置、文字格式、插入圖片、表格製作、數學公式、指令碼等基礎主題。Page setup, text formatting, images, tables, math, and scripting.","link":"/guide/"},{"icon":"🎨","title":"動手練習 / Hands-on Practice","details":"每個章節結尾都有練習題，幫助鞏固所學。Exercises at the end of each chapter to reinforce learning.","link":"/guide/page-setup"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),l={name:"index.md"};function r(n,a,o,p,c,d){return e(),i("div",null,[...a[0]||(a[0]=[s('<h2 id="這是一個什麼樣的網站-what-is-this-site" tabindex="-1">這是一個什麼樣的網站？ / What is this site? <a class="header-anchor" href="#這是一個什麼樣的網站-what-is-this-site" aria-label="Permalink to &quot;這是一個什麼樣的網站？ / What is this site?&quot;">​</a></h2><div class="bilingual-block"><div class="zh-block"><span class="lang-label">中文</span><p><strong>Typst 練習場</strong> 是一個專門為初學者設計的 Typst 排版語言學習網站。無論你是第一次接觸 Typst，還是想從 LaTeX、Word 或 Markdown 遷移到 Typst，這裡都有你需要的資源。</p><p>每個主題都提供：</p><ul><li>清晰的語法說明與範例</li><li>繁體中文與英文雙語對照</li><li>實踐練習題</li><li>互動沙盒隨時試驗</li></ul></div><div class="en-block"><span class="lang-label">English</span><p><strong>Typst Practice</strong> is a learning site designed specifically for beginners to learn the Typst typesetting language. Whether you&#39;re new to Typst or migrating from LaTeX, Word, or Markdown, you&#39;ll find what you need here.</p><p>Each topic provides:</p><ul><li>Clear syntax explanations and examples</li><li>Traditional Chinese and English bilingual content</li><li>Hands-on practice exercises</li><li>Interactive sandbox to experiment anytime</li></ul></div></div><hr><h2 id="什麼是-typst-what-is-typst" tabindex="-1">什麼是 Typst？ / What is Typst? <a class="header-anchor" href="#什麼是-typst-what-is-typst" aria-label="Permalink to &quot;什麼是 Typst？ / What is Typst?&quot;">​</a></h2><div class="bilingual-block"><div class="zh-block"><span class="lang-label">中文</span><p><strong>Typst</strong> 是一種基於標記（markup）的新型排版系統，結合了輕量級標記語法與強大的指令碼功能。與 LaTeX 相比，Typst 更易學易用，同時保持專業排版品質。</p><ul><li>內建常見格式的標記語法</li><li>靈活的函數系統</li><li>緊密集成的指令碼功能</li><li>數學排版、參考文獻管理</li><li><strong>極快的增量編譯速度</strong></li><li><strong>友好的錯誤訊息</strong></li></ul></div><div class="en-block"><span class="lang-label">English</span><p><strong>Typst</strong> is a new markup-based typesetting system that combines lightweight markup syntax with powerful scripting capabilities. Compared to LaTeX, Typst is easier to learn and use while maintaining professional typesetting quality.</p><ul><li>Built-in markup for common formatting</li><li>Flexible function system</li><li>Tightly integrated scripting</li><li>Math typesetting, bibliography management</li><li><strong>Extremely fast incremental compilation</strong></li><li><strong>Friendly error messages</strong></li></ul></div></div><hr><h2 id="開始學習路線-learning-path" tabindex="-1">開始學習路線 / Learning Path <a class="header-anchor" href="#開始學習路線-learning-path" aria-label="Permalink to &quot;開始學習路線 / Learning Path&quot;">​</a></h2><div class="feature-grid"><div class="feature-card"><h3>1. 快速入門 / Quick Start</h3><p>了解 Typst 的基本概念，撰寫你的第一份文件。</p><a href="/guide/quick-start" class="tag">開始 →</a></div><div class="feature-card"><h3>2. 頁面設置 / Page Setup</h3><p>學習如何設定頁面大小、邊距、方向等基本參數。</p><a href="/guide/page-setup" class="tag">開始 →</a></div><div class="feature-card"><h3>3. 文字格式 / Text Formatting</h3><p>掌握粗體、斜體、字型、顏色等文字樣式。</p><a href="/guide/text-formatting" class="tag">開始 →</a></div><div class="feature-card"><h3>4. 圖片 / Images</h3><p>插入與調整圖片，設定標題與引用。</p><a href="/guide/images" class="tag">開始 →</a></div><div class="feature-card"><h3>5. 表格 / Tables</h3><p>建立格式化的表格，合併儲存格與自訂樣式。</p><a href="/guide/tables" class="tag">開始 →</a></div><div class="feature-card"><h3>6. 數學 / Math</h3><p>撰寫美觀的數學公式，從基礎到進階。</p><a href="/guide/math-basics" class="tag">開始 →</a></div><div class="feature-card"><h3>7. 指令碼 / Scripting</h3><p>使用變數、迴圈、條件判斷來讓文件更聰明。</p><a href="/guide/scripting-intro" class="tag">開始 →</a></div><div class="feature-card"><h3>8. 沙盒 / Sandbox</h3><p>自由實驗 Typst 程式碼，即時看到結果。</p><a href="/sandbox/" class="tag">開始 →</a></div></div><hr><h2 id="外部資源-external-resources" tabindex="-1">外部資源 / External Resources <a class="header-anchor" href="#外部資源-external-resources" aria-label="Permalink to &quot;外部資源 / External Resources&quot;">​</a></h2><div class="bilingual-block"><div class="zh-block"><span class="lang-label">中文資源</span><ul><li><a href="https://typst-doc-cn.github.io/guide/" target="_blank" rel="noreferrer">Typst 中文社區導航</a></li><li><a href="https://typst-doc-cn.github.io/tutorial/" target="_blank" rel="noreferrer">小藍書 — 入門教程</a></li><li><a href="https://typst-doc-cn.github.io/docs/" target="_blank" rel="noreferrer">Typst 中文文檔</a></li></ul></div><div class="en-block"><span class="lang-label">English Resources</span><ul><li><a href="https://typst.app/docs/" target="_blank" rel="noreferrer">Official Typst Documentation</a></li><li><a href="https://typst.app/docs/tutorial/" target="_blank" rel="noreferrer">Typst Tutorial</a></li><li><a href="https://typst.app/universe/" target="_blank" rel="noreferrer">Typst Universe (Packages)</a></li><li><a href="https://github.com/typst/typst" target="_blank" rel="noreferrer">Typst GitHub (Compiler)</a></li></ul></div></div>',11)])])}const u=t(l,[["render",r]]);export{g as __pageData,u as default};
